-- Crown Point Energy -- Comunicados de Prensa (historic seed)
-- Source: crownpointenergy.com · Scraped 2026-06-29
-- 250 rows: 220 EN press releases + 53 ES comunicados
-- Safe to re-run: ON CONFLICT (url) DO NOTHING

-- Add url_pdf column if it doesn't exist (stores external PDF link)
ALTER TABLE comunicados ADD COLUMN IF NOT EXISTS url_pdf TEXT NOT NULL DEFAULT '';

-- Add unique constraint on url (safe if it already exists)
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint WHERE conname = 'comunicados_url_key'
  ) THEN
    ALTER TABLE comunicados ADD CONSTRAINT comunicados_url_key UNIQUE (url);
  END IF;
END $$;

ON CONFLICT (url) DO NOTHING;
